#include <bits/stdc++.h>using namespace std;typedef long long ll;int main(){    ll t;    cin>>t;    while(t--){      ll n;      cin>>n;      map<ll,ll> mp;      ll mx=0;      for(int i=0;i<n;i++){        for(int i=0;i<n;i++){          ll x;          cin>>x;          mp[x]++;          mx=max(mx,mp[x]);        }      }      if(mx<=(n*n)-n){        cout<<"YES"<<endl;      }      else{        cout<<"NO"<<endl;      }    }}